 10→struct TrainerListView: View {
 11→    @Bindable var viewModel: PersonalTrainerViewModel
 12→    let onTrainerSelected: (PersonalTrainer) -> Void
 13→
 14→    var body: some View {
 15→        VStack(spacing: 0) {
 16→            // Search Bar
 17→            searchBar
 18→                .padding(.horizontal, FitTodaySpacing.md)
 19→                .padding(.vertical, FitTodaySpacing.sm)
 20→
 21→            ScrollView {
 22→                LazyVStack(spacing: FitTodaySpacing.md) {
 23→                    if viewModel.isSearching {
 24→                        ProgressView()
 25→                            .tint(FitTodayColor.brandPrimary)
 26→                            .frame(maxWidth: .infinity)
 27→                            .padding(.top, FitTodaySpacing.xl)
 28→                    } else if viewModel.searchResults.isEmpty && !viewModel.searchQuery.isEmpty {
 29→                        emptyResultsView
 30→                    } else {
 31→                        ForEach(viewModel.searchResults) { trainer in
 32→                            TrainerRatingCard(
 33→                                trainer: trainer,
 34→                                onConnect: { onTrainerSelected(trainer) },
 35→                                onSelect: { onTrainerSelected(trainer) }
 36→                            )
 37→                        }
 38→                    }
 39→                }
 40→                .padding(.horizontal, FitTodaySpacing.md)
 41→                .padding(.bottom, FitTodaySpacing.xl)
 42→            }
 43→            .scrollIndicators(.hidden)
 44→        }
 45→        .background(FitTodayColor.background)
 46→        .onAppear {
 47→            if viewModel.searchResults.isEmpty {
 48→                Task { await viewModel.searchTrainers() }
 49→            }
 50→        }
 51→    }
 52→
 53→    // MARK: - Search Bar
 54→
 55→    private var searchBar: some View {
 56→        HStack(spacing: FitTodaySpacing.sm) {
 57→            Image(systemName: "magnifyingglass")
 58→                .font(.system(size: 16))
 59→                .foregroundStyle(FitTodayColor.textSecondary)
 60→
 61→            TextField("trainer.list.search_placeholder".localized, text: $viewModel.searchQuery)
 62→                .font(FitTodayFont.ui(size: 14, weight: .medium))
 63→                .foregroundStyle(FitTodayColor.textPrimary)
 64→                .autocorrectionDisabled()
 65→
 66→            if !viewModel.searchQuery.isEmpty {
 67→                Button {
 68→                    viewModel.clearSearch()
 69→                } label: {
 70→                    Image(systemName: "xmark.circle.fill")
 71→                        .font(.system(size: 16))
 72→                        .foregroundStyle(FitTodayColor.textTertiary)
 73→                }
 74→                .buttonStyle(.plain)
 75→            }
 76→        }
 77→        .padding(.horizontal, FitTodaySpacing.md)
 78→        .padding(.vertical, 10)
 79→        .background(FitTodayColor.surface)
 80→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
 81→        .onChange(of: viewModel.searchQuery) {
 82→            Task {
 83→                try? await Task.sleep(for: .milliseconds(500))
 84→                guard !Task.isCancelled else { return }
 85→                await viewModel.searchTrainers()
 86→            }
 87→        }
 88→    }
 89→
 90→    // MARK: - Empty Results
 91→
 92→    private var emptyResultsView: some View {
 93→        VStack(spacing: FitTodaySpacing.md) {
 94→            Image(systemName: "magnifyingglass")
 95→                .font(.system(size: 40))
 96→                .foregroundStyle(FitTodayColor.textTertiary)
 97→
 98→            Text("trainer.list.no_results".localized)
 99→                .font(FitTodayFont.ui(size: 16, weight: .semiBold))
100→                .foregroundStyle(FitTodayColor.textPrimary)
101→
102→            Text("trainer.list.no_results_message".localized)
103→                .font(FitTodayFont.ui(size: 14, weight: .medium))
104→                .foregroundStyle(FitTodayColor.textSecondary)
105→                .multilineTextAlignment(.center)
106→        }
107→        .padding(.top, FitTodaySpacing.xxl)
108→    }
109→}
