169→                    }
170→                }
171→                .fitPrimaryStyle()
172→
173→                // Invite Code Section
174→                VStack(spacing: FitTodaySpacing.sm) {
175→                    Text("personal_trainer.invite.header".localized)
176→                        .font(FitTodayFont.ui(size: 14, weight: .medium))
177→                        .foregroundStyle(FitTodayColor.textSecondary)
178→
179→                    HStack(spacing: FitTodaySpacing.sm) {
180→                        TextField("personal_trainer.invite.placeholder".localized, text: $viewModel.inviteCode)
181→                            .textFieldStyle(.roundedBorder)
