249→    // MARK: - Connected Trainer Section
250→
251→    private var connectedTrainerSection: some View {
252→        VStack(spacing: FitTodaySpacing.lg) {
253→            if let trainer = viewModel.currentTrainer {
254→                // Trainer Card
255→                TrainerCard(trainer: trainer, variant: .expanded)
256→
257→                // Connection Status
258→                connectionStatusBadge
259→
260→                // Assigned Workouts
261→                if viewModel.isConnected {
262→                    assignedWorkoutsSection
263→                }
264→
265→                // Actions
