271→    // MARK: - Connection Status Badge
272→
273→    private var connectionStatusBadge: some View {
274→        HStack(spacing: FitTodaySpacing.sm) {
275→            Circle()
276→                .fill(statusColor)
277→                .frame(width: 8, height: 8)
278→
279→            Text(statusText)
280→                .font(FitTodayFont.ui(size: 14, weight: .medium))
281→                .foregroundStyle(FitTodayColor.textSecondary)
282→        }
283→        .padding(.horizontal, FitTodaySpacing.md)
284→        .padding(.vertical, FitTodaySpacing.sm)
285→        .background(statusColor.opacity(0.1))
286→        .clipShape(Capsule())
287→    }
288→
289→    private var statusColor: Color {
290→        switch viewModel.connectionStatus {
291→        case .active: return FitTodayColor.success
292→        case .pending: return FitTodayColor.warning
293→        case .paused: return FitTodayColor.info
294→        case .cancelled: return FitTodayColor.error
295→        case .none: return FitTodayColor.textSecondary
296→        }
297→    }
298→
299→    private var statusText: String {
300→        switch viewModel.connectionStatus {
301→        case .active: return "personal_trainer.status.active".localized
302→        case .pending: return "personal_trainer.status.pending".localized
303→        case .paused: return "personal_trainer.status.paused".localized
304→        case .cancelled: return "personal_trainer.status.cancelled".localized
305→        case .none: return "personal_trainer.status.none".localized
306→        }
307→    }
308→
