344→                    .buttonStyle(.plain)
345→                }
346→            }
347→        }
348→        .padding()
349→        .background(FitTodayColor.surface)
350→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.lg))
351→    }
352→
353→    // MARK: - Connection Actions Section
354→
355→    private var connectionActionsSection: some View {
356→        VStack(spacing: FitTodaySpacing.sm) {
357→            if viewModel.isPending {
358→                Button {
359→                    Task {
360→                        await viewModel.cancelConnection()
361→                    }
362→                } label: {
363→                    HStack {
364→                        Image(systemName: "xmark.circle")
365→                        Text("personal_trainer.actions.cancel_request".localized)
