386→// MARK: - Assigned Workout Row
387→
388→private struct AssignedWorkoutRow: View {
389→    let workout: TrainerWorkout
390→
391→    private var exerciseCount: Int {
392→        workout.phases.reduce(0) { $0 + $1.items.count }
393→    }
394→
395→    private var scheduledDate: Date? {
396→        workout.schedule.scheduledDate
397→    }
398→
399→    var body: some View {
400→        HStack(spacing: FitTodaySpacing.md) {
401→            // Icon
402→            ZStack {
403→                Circle()
404→                    .fill(workout.isActive ? FitTodayColor.brandPrimary.opacity(0.1) : FitTodayColor.textSecondary.opacity(0.1))
405→                    .frame(width: 44, height: 44)
406→
407→                Image(systemName: workout.isActive ? "dumbbell.fill" : "checkmark.circle.fill")
408→                    .font(.system(size: 20))
409→                    .foregroundStyle(workout.isActive ? FitTodayColor.brandPrimary : FitTodayColor.success)
410→            }
411→
412→            // Content
413→            VStack(alignment: .leading, spacing: 4) {
414→                Text(workout.title)
415→                    .font(FitTodayFont.ui(size: 16, weight: .semiBold))
416→                    .foregroundStyle(FitTodayColor.textPrimary)
417→                    .lineLimit(1)
418→
419→                HStack(spacing: FitTodaySpacing.sm) {
420→                    Text("personal_trainer.workouts.exercises_count".localized(with: exerciseCount))
421→                        .font(FitTodayFont.ui(size: 12, weight: .medium))
422→                        .foregroundStyle(FitTodayColor.textSecondary)
423→
424→                    if let scheduledDate = scheduledDate {
425→                        Text("- \(scheduledDate.formatted(date: .abbreviated, time: .omitted))")
426→                            .font(FitTodayFont.ui(size: 12, weight: .medium))
427→                            .foregroundStyle(FitTodayColor.textSecondary)
428→                    }
429→                }
430→            }
431→
432→            Spacer()
433→
434→            Image(systemName: "chevron.right")
435→                .font(.system(size: 14, weight: .medium))
436→                .foregroundStyle(FitTodayColor.textSecondary)
437→        }
438→        .padding()
439→        .background(FitTodayColor.background)
440→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
441→    }
442→}
