 4→//
 5→//  CMS-backed implementation of PersonalTrainerRepository.
 6→//  Fetches trainers from the CMS API instead of Firebase.
 7→//
 8→
 9→import Foundation
10→
11→final class CMSPersonalTrainerRepository: PersonalTrainerRepository, @unchecked Sendable {
12→
13→    private let service: CMSTrainerService
14→
15→    init(service: CMSTrainerService) {
16→        self.service = service
17→    }
18→
19→    func fetchTrainer(id: String) async throws -> PersonalTrainer {
20→        let dto = try await service.fetchTrainer(id: id)
21→        return CMSTrainerMapper.toDomain(dto)
22→    }
23→
24→    func searchTrainers(query: String, limit: Int) async throws -> [PersonalTrainer] {
25→        let response = try await service.fetchTrainers(limit: limit, offset: 0)
26→        // Sort: trainers with photos first, then alphabetically
27→        let trainers = response.trainers
28→            .sorted { lhs, rhs in
29→                let lhasPhoto = lhs.photoURL != nil && !(lhs.photoURL?.isEmpty ?? true)
30→                let rhasPhoto = rhs.photoURL != nil && !(rhs.photoURL?.isEmpty ?? true)
31→                if lhasPhoto != rhasPhoto { return lhasPhoto }
32→                return lhs.displayName < rhs.displayName
33→            }
34→            .map { CMSTrainerMapper.toDomain($0) }
35→
36→        guard !query.isEmpty else { return trainers }
37→        let normalized = query.lowercased()
38→        return trainers.filter { $0.displayName.lowercased().contains(normalized) }
39→    }
40→
41→    func findByInviteCode(_ code: String) async throws -> PersonalTrainer? {
42→        // CMS doesn't have a dedicated invite code endpoint yet.
43→        // Fetch all trainers and filter locally as a fallback.
44→        let response = try await service.fetchTrainers(limit: 100, offset: 0)
45→        return response.trainers
46→            .first { $0.inviteCode?.uppercased() == code.uppercased() }
47→            .map { CMSTrainerMapper.toDomain($0) }
48→    }
49→}
