//
//  EntitlementPolicy.swift
//  FitToday
//
//  Política centralizada de acesso a features baseada no entitlement.
//

import Foundation

// MARK: - Feature Enum

/// Features que requerem verificação de acesso
enum ProFeature: String, CaseIterable {
    // Treinos IA
    case aiWorkoutGeneration = "ai_workout_generation"
    case aiExerciseSubstitution = "ai_exercise_substitution"

    // Tracking avançado
    case unlimitedHistory = "unlimited_history"
    case advancedDOMSAdjustment = "advanced_doms_adjustment"

    // Biblioteca
    case premiumPrograms = "premium_programs"

    // Configurações
    case customizableSettings = "customizable_settings"

    // Personal Trainer
    case personalTrainer = "personal_trainer"
    case trainerWorkouts = "trainer_workouts"

    // Social
    case simultaneousChallenges = "simultaneous_challenges"

    // AI Chat
    case aiChat = "ai_chat"

    var displayName: String {
        switch self {
        case .aiWorkoutGeneration: return "Treinos personalizados por IA"
        case .aiExerciseSubstitution: return "Substituição inteligente de exercícios"
        case .unlimitedHistory: return "Histórico ilimitado"
        case .advancedDOMSAdjustment: return "Ajuste por dor muscular"
        case .premiumPrograms: return "Programas premium"
        case .customizableSettings: return "Configurações avançadas"
        case .personalTrainer: return "Personal Trainer"
        case .trainerWorkouts: return "Treinos do Personal"
        case .simultaneousChallenges: return "Desafios simultâneos ilimitados"
        case .aiChat: return "Assistente IA FitOrb"
        }
    }
}

// MARK: - Access Result

/// Resultado da verificação de acesso
enum FeatureAccessResult {
    case allowed
    case limitReached(remaining: Int, limit: Int)
    case requiresPro(feature: ProFeature)
    case requiresElite(feature: ProFeature)
    case trialExpired
    case featureDisabled(reason: String)

    var isAllowed: Bool {
        if case .allowed = self { return true }
        return false
    }

    /// Indicates if the result is due to a disabled feature flag.
    var isFeatureDisabled: Bool {
        if case .featureDisabled = self { return true }
        return false
    }

    var message: String {
        switch self {
        case .allowed:
            return ""
        case .limitReached(_, let limit):
            return "Você atingiu o limite de \(limit) usos. Desbloqueie o Pro para mais."
        case .requiresPro(let feature):
            return "\(feature.displayName) é um recurso Pro. Desbloqueie o Pro para acessar."
        case .requiresElite(let feature):
            return "\(feature.displayName) é exclusivo do plano Elite. Faça upgrade para acessar."
        case .trialExpired:
            return "Seu período de teste terminou. Desbloqueie o Pro para continuar."
        case .featureDisabled(let reason):
            return reason
        }
    }
}

// MARK: - Entitlement Policy

/// Política centralizada para verificação de acesso a features
struct EntitlementPolicy {

    // MARK: - Limites

    /// Número de treinos IA por semana para usuários Free
    static let freeAIWorkoutsPerWeek = 1

    /// Número de treinos IA por dia para usuários Pro
    static let proAIWorkoutsPerDay = 2

    /// Dias de histórico para usuários Free
    static let freeHistoryDaysLimit = 7

    /// Número máximo de desafios simultâneos para Free
    static let freeChallengesLimit = 5

    /// Numero de mensagens AI chat por dia para usuarios Free
    static let freeAIChatMessagesPerDay = 2

    // MARK: - Verificação de Acesso

    /// Verifica se o usuário pode acessar uma feature
    /// - Parameters:
    ///   - feature: Feature a ser verificada
    ///   - entitlement: Entitlement atual do usuário
    ///   - usageCount: Uso atual (semanal para Free AI, diário para Pro AI, contagem ativa para desafios)
    /// - Returns: Resultado da verificação
    static func canAccess(
        _ feature: ProFeature,
        entitlement: ProEntitlement,
        usageCount: Int = 0
    ) -> FeatureAccessResult {

        // Subscription expired
        if entitlement.isPro,
           let expiration = entitlement.expirationDate,
           expiration < Date() {
            return .trialExpired
        }

        // Elite — acesso irrestrito a tudo
        if entitlement.isElite {
            return .allowed
        }

        // Pro — acesso com limites diários em IA (Personal Trainer é Elite-only)
        if entitlement.isPro {
            switch feature {
            case .aiWorkoutGeneration:
                if usageCount >= proAIWorkoutsPerDay {
                    return .limitReached(remaining: 0, limit: proAIWorkoutsPerDay)
                }
                return .allowed
            case .personalTrainer, .trainerWorkouts:
                return .requiresElite(feature: feature)
            default:
                return .allowed
            }
        }

        // Free — verificar features específicas
        switch feature {
        case .aiWorkoutGeneration:
            if usageCount >= freeAIWorkoutsPerWeek {
                return .limitReached(remaining: 0, limit: freeAIWorkoutsPerWeek)
            }
            return .allowed

        case .simultaneousChallenges:
            if usageCount >= freeChallengesLimit {
                return .limitReached(remaining: 0, limit: freeChallengesLimit)
            }
            return .allowed

        case .aiChat:
            if usageCount >= freeAIChatMessagesPerDay {
                return .limitReached(remaining: 0, limit: freeAIChatMessagesPerDay)
            }
            return .allowed

        case .personalTrainer, .trainerWorkouts:
            return .requiresElite(feature: feature)

        case .aiExerciseSubstitution,
             .unlimitedHistory,
             .advancedDOMSAdjustment,
             .premiumPrograms,
             .customizableSettings:
            return .requiresPro(feature: feature)
        }
    }

    /// Verifica se uma feature é totalmente bloqueada para Free (requer Pro ou Elite)
    static func isProOnly(_ feature: ProFeature) -> Bool {
        switch feature {
        case .aiWorkoutGeneration, .simultaneousChallenges, .aiChat:
            return false // Free tem acesso limitado
        case .personalTrainer, .trainerWorkouts:
            return false // Elite-only, não Pro-only
        case .aiExerciseSubstitution,
             .unlimitedHistory,
             .advancedDOMSAdjustment,
             .premiumPrograms,
             .customizableSettings:
            return true
        }
    }

    /// Verifica se uma feature é exclusiva do plano Elite
    static func isEliteOnly(_ feature: ProFeature) -> Bool {
        switch feature {
        case .personalTrainer, .trainerWorkouts:
            return true
        default:
            return false
        }
    }

    /// Retorna o limite de uso para uma feature
    static func usageLimit(for feature: ProFeature, entitlement: ProEntitlement) -> (limit: Int, period: String)? {
        switch feature {
        case .aiWorkoutGeneration:
            if entitlement.isPro {
                return (proAIWorkoutsPerDay, "dia")
            } else {
                return (freeAIWorkoutsPerWeek, "semana")
            }
        case .simultaneousChallenges:
            if entitlement.isPro {
                return nil // ilimitado
            } else {
                return (freeChallengesLimit, "simultâneos")
            }
        case .aiChat:
            if entitlement.isPro {
                return nil // ilimitado
            } else {
                return (freeAIChatMessagesPerDay, "dia")
            }
        default:
            return nil
        }
    }

    // MARK: - Helpers para UI

    /// Retorna lista de features que são Pro-only para exibição
    static var proOnlyFeatures: [ProFeature] {
        ProFeature.allCases.filter { isProOnly($0) }
    }

    /// Retorna lista de features com limites para Free
    static var limitedFreeFeatures: [(feature: ProFeature, freeLimit: String, proLimit: String)] {
        [
            (.aiWorkoutGeneration, "1/semana", "2/dia"),
            (.simultaneousChallenges, "5", "∞"),
            (.aiChat, "2/dia", "ilimitado")
        ]
    }
}

// MARK: - Convenience Extensions

extension ProEntitlement {
    /// Verifica acesso a uma feature usando a policy centralizada
    func canAccess(_ feature: ProFeature, usageCount: Int = 0) -> FeatureAccessResult {
        EntitlementPolicy.canAccess(feature, entitlement: self, usageCount: usageCount)
    }

    /// Verifica se tem acesso a uma feature (simplificado)
    func hasAccess(to feature: ProFeature) -> Bool {
        canAccess(feature).isAllowed
    }
}

//
//  PersonalTrainerViewModel.swift
//  FitToday
//
//  Created by AI on 04/02/26.
//

import Foundation
import Swinject

@Observable
@MainActor
final class PersonalTrainerViewModel {
    // MARK: - State

    private(set) var currentTrainer: PersonalTrainer?
    private(set) var connectionStatus: TrainerConnectionStatus?
    private(set) var relationshipId: String?
    private(set) var assignedWorkouts: [TrainerWorkout] = []
    private(set) var searchResults: [PersonalTrainer] = []
    var searchQuery: String = ""
    var inviteCode: String = ""
    private(set) var isLoading: Bool = false
    private(set) var isSearching: Bool = false
    private(set) var isRequestingConnection: Bool = false
    private(set) var error: Error?
    var showConnectionSheet: Bool = false
    var selectedTrainer: PersonalTrainer?
    private(set) var isFeatureEnabled: Bool = false
    private(set) var isChatEnabled: Bool = false
    private(set) var currentUserId: String = ""

    // MARK: - Dependencies

    private let discoverTrainersUseCase: DiscoverTrainersUseCaseProtocol?
    private let requestConnectionUseCase: RequestTrainerConnectionUseCaseProtocol?
    private let cancelConnectionUseCase: CancelTrainerConnectionUseCaseProtocol?
    private let getCurrentTrainerUseCase: GetCurrentTrainerUseCaseProtocol?
    private let fetchAssignedWorkoutsUseCase: FetchAssignedWorkoutsUseCaseProtocol?
    private let fetchCMSWorkoutsUseCase: FetchCMSWorkoutsUseCase?
    private let featureFlagChecker: FeatureFlagChecking?
    private let cmsWorkoutRepository: CMSWorkoutRepository?
    private let authRepository: AuthenticationRepository?

    private var observationTask: Task<Void, Never>?
    private var workoutsObservationTask: Task<Void, Never>?

    // MARK: - Initialization

    init(resolver: Resolver) {
        self.discoverTrainersUseCase = resolver.resolve(DiscoverTrainersUseCaseProtocol.self)
        self.requestConnectionUseCase = resolver.resolve(RequestTrainerConnectionUseCaseProtocol.self)
        self.cancelConnectionUseCase = resolver.resolve(CancelTrainerConnectionUseCaseProtocol.self)
        self.getCurrentTrainerUseCase = resolver.resolve(GetCurrentTrainerUseCaseProtocol.self)
        self.fetchAssignedWorkoutsUseCase = resolver.resolve(FetchAssignedWorkoutsUseCaseProtocol.self)
        self.fetchCMSWorkoutsUseCase = resolver.resolve(FetchCMSWorkoutsUseCase.self)
        self.featureFlagChecker = resolver.resolve(FeatureFlagChecking.self)
        self.cmsWorkoutRepository = resolver.resolve(CMSWorkoutRepository.self)
        self.authRepository = resolver.resolve(AuthenticationRepository.self)
    }

    // For testing
    init(
        discoverTrainersUseCase: DiscoverTrainersUseCaseProtocol? = nil,
        requestConnectionUseCase: RequestTrainerConnectionUseCaseProtocol? = nil,
        cancelConnectionUseCase: CancelTrainerConnectionUseCaseProtocol? = nil,
        getCurrentTrainerUseCase: GetCurrentTrainerUseCaseProtocol? = nil,
        fetchAssignedWorkoutsUseCase: FetchAssignedWorkoutsUseCaseProtocol? = nil,
        fetchCMSWorkoutsUseCase: FetchCMSWorkoutsUseCase? = nil,
        featureFlagChecker: FeatureFlagChecking? = nil,
        cmsWorkoutRepository: CMSWorkoutRepository? = nil,
        authRepository: AuthenticationRepository? = nil
    ) {
        self.discoverTrainersUseCase = discoverTrainersUseCase
        self.requestConnectionUseCase = requestConnectionUseCase
        self.cancelConnectionUseCase = cancelConnectionUseCase
        self.getCurrentTrainerUseCase = getCurrentTrainerUseCase
        self.fetchAssignedWorkoutsUseCase = fetchAssignedWorkoutsUseCase
        self.fetchCMSWorkoutsUseCase = fetchCMSWorkoutsUseCase
        self.featureFlagChecker = featureFlagChecker
        self.cmsWorkoutRepository = cmsWorkoutRepository
        self.authRepository = authRepository
    }

    // Note: Task cancellation is handled by onDisappear()
    // deinit removed to avoid @MainActor isolation issues

    // MARK: - Computed Properties

    var isConnected: Bool {
        connectionStatus == .active
    }

    var isPending: Bool {
        connectionStatus == .pending
    }

    var hasTrainer: Bool {
        currentTrainer != nil
    }

    var canSearch: Bool {
        !searchQuery.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    var canUseInviteCode: Bool {
        !inviteCode.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    var pendingWorkoutsCount: Int {
        assignedWorkouts.filter { $0.isActive }.count
    }

    // MARK: - Lifecycle

    func onAppear() {
        Task {
            await loadCurrentUserId()
            await checkFeatureFlag()
            if isFeatureEnabled {
                await loadCurrentTrainer()
                startObservingRelationship()
                startObservingWorkouts()
            }
        }
    }

    private func loadCurrentUserId() async {
        guard let authRepo = authRepository else { return }
        currentUserId = (try? await authRepo.currentUser()?.id) ?? ""
    }

    func onDisappear() {
        observationTask?.cancel()
        workoutsObservationTask?.cancel()
    }

    // MARK: - Feature Flag

    private func checkFeatureFlag() async {
        guard let checker = featureFlagChecker else {
            isFeatureEnabled = false
            return
        }
        isFeatureEnabled = await checker.isFeatureEnabled(.personalTrainerEnabled)
        isChatEnabled = await checker.isFeatureEnabled(.trainerChatEnabled)
    }

    // MARK: - Load Current Trainer

    func loadCurrentTrainer() async {
        guard let useCase = getCurrentTrainerUseCase else {
            #if DEBUG
            print("[PersonalTrainerViewModel] GetCurrentTrainerUseCase not available")
            #endif
            return
        }

        isLoading = true
        error = nil

        do {
            if let result = try await useCase.execute() {
                currentTrainer = result.trainer
                connectionStatus = result.relationship.status
                relationshipId = result.relationship.id
                await loadAssignedWorkouts()
            } else {
                currentTrainer = nil
                connectionStatus = nil
                relationshipId = nil
                assignedWorkouts = []
            }
        } catch {
            self.error = error
            #if DEBUG
            print("[PersonalTrainerViewModel] Error loading trainer: \(error)")
            #endif
        }

        isLoading = false
    }

    // MARK: - Search Trainers

    func searchTrainers() async {
        guard let useCase = discoverTrainersUseCase else {
            #if DEBUG
            print("[PersonalTrainerViewModel] DiscoverTrainersUseCase not available")
            #endif
            return
        }

        let query = searchQuery.trimmingCharacters(in: .whitespacesAndNewlines)

        isSearching = true
        error = nil

        do {
            if query.isEmpty {
                // Load all active trainers from CMS marketplace
                searchResults = try await useCase.searchByName("", limit: 20)
            } else {
                searchResults = try await useCase.searchByName(query, limit: 20)
            }
        } catch {
            self.error = error
            searchResults = []
            #if DEBUG
            print("[PersonalTrainerViewModel] Error searching trainers: \(error)")
            #endif
        }

        isSearching = false
    }

    // MARK: - Find by Invite Code

    func findByInviteCode() async {
        guard let useCase = discoverTrainersUseCase else {
            #if DEBUG
            print("[PersonalTrainerViewModel] DiscoverTrainersUseCase not available")
            #endif
            return
        }

        let code = inviteCode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !code.isEmpty else {
            return
        }

        isSearching = true
        error = nil

        do {
            if let trainer = try await useCase.findByInviteCode(code) {
                selectedTrainer = trainer
                showConnectionSheet = true
            } else {
                error = PersonalTrainerError.invalidInviteCode
            }
        } catch {
            self.error = error
            #if DEBUG
            print("[PersonalTrainerViewModel] Error finding by invite code: \(error)")
            #endif
        }

        isSearching = false
    }

    // MARK: - Request Connection

    func requestConnection(to trainer: PersonalTrainer) async -> Bool {
        guard let useCase = requestConnectionUseCase else {
            #if DEBUG
            print("[PersonalTrainerViewModel] RequestTrainerConnectionUseCase not available")
            #endif
            return false
        }

        isRequestingConnection = true
        error = nil

        do {
            let newRelationshipId = try await useCase.execute(trainerId: trainer.id)
            relationshipId = newRelationshipId
            currentTrainer = trainer
            connectionStatus = .pending
            showConnectionSheet = false
            selectedTrainer = nil
            searchResults = []
            searchQuery = ""
            inviteCode = ""
            isRequestingConnection = false

            // Register student in CMS so the trainer can assign workouts
            await registerStudentInCMS(trainerId: trainer.id)

            isRequestingConnection = false
            return true
        } catch {
            self.error = error
            isRequestingConnection = false
            #if DEBUG
            print("[PersonalTrainerViewModel] Error requesting connection: \(error)")
            #endif
            return false
        }
    }

    // MARK: - CMS Student Registration

    /// Registers the student in the CMS after a successful Firebase connection.
    /// This is best-effort — failure does not block the connection flow.
    private func registerStudentInCMS(trainerId: String) async {
        guard let repo = cmsWorkoutRepository,
              let authRepo = authRepository else {
            #if DEBUG
            print("[PersonalTrainerViewModel] CMS registration skipped: dependencies not available")
            #endif
            return
        }

        do {
            guard let user = try await authRepo.currentUser() else {
                #if DEBUG
                print("[PersonalTrainerViewModel] CMS registration skipped: no current user")
                #endif
                return
            }

            try await repo.registerStudent(
                firebaseUid: user.id,
                trainerId: trainerId,
                displayName: user.displayName,
                email: user.email
            )

            #if DEBUG
            print("[PersonalTrainerViewModel] Student registered in CMS for trainer \(trainerId)")
            #endif
        } catch {
            #if DEBUG
            print("[PersonalTrainerViewModel] CMS registration failed (non-blocking): \(error)")
            #endif
        }
    }

    // MARK: - Cancel Connection

    func cancelConnection() async -> Bool {
        guard let useCase = cancelConnectionUseCase,
              let relId = relationshipId else {
            #if DEBUG
            print("[PersonalTrainerViewModel] CancelTrainerConnectionUseCase not available or no relationship")
            #endif
            return false
        }

        isLoading = true
        error = nil

        do {
            try await useCase.execute(relationshipId: relId)
            currentTrainer = nil
            connectionStatus = nil
            relationshipId = nil
            assignedWorkouts = []
            isLoading = false
            return true
        } catch {
            self.error = error
            isLoading = false
            #if DEBUG
            print("[PersonalTrainerViewModel] Error canceling connection: \(error)")
            #endif
            return false
        }
    }

    // MARK: - Load Assigned Workouts

    private func loadAssignedWorkouts() async {
        // Try CMS workouts first (primary source)
        if let cmsUseCase = fetchCMSWorkoutsUseCase {
            do {
                let result = try await cmsUseCase.execute()
                assignedWorkouts = result.workouts
                #if DEBUG
                print("[PersonalTrainerViewModel] Loaded \(result.workouts.count) CMS workouts")
                #endif
                return
            } catch {
                #if DEBUG
                print("[PersonalTrainerViewModel] CMS workouts failed, falling back to Firebase: \(error)")
                #endif
            }
        }

        // Fallback to Firebase workouts
        guard let useCase = fetchAssignedWorkoutsUseCase else {
            return
        }

        do {
            assignedWorkouts = try await useCase.execute()
        } catch {
            #if DEBUG
            print("[PersonalTrainerViewModel] Error loading workouts: \(error)")
            #endif
        }
    }

    // MARK: - Observation

    private func startObservingRelationship() {
        observationTask?.cancel()
        observationTask = Task {
            guard let useCase = getCurrentTrainerUseCase else { return }

            for await relationship in useCase.observeRelationship() {
                guard !Task.isCancelled else { break }

                if let rel = relationship, rel.status != .cancelled {
                    connectionStatus = rel.status
                    relationshipId = rel.id

                    // Reload trainer if status changed to active
                    if rel.status == .active && currentTrainer == nil {
                        await loadCurrentTrainer()
                    }
                } else {
                    // nil or cancelled — treat as no trainer
                    currentTrainer = nil
                    connectionStatus = nil
                    relationshipId = nil
                }
            }
        }
    }

    private func startObservingWorkouts() {
        workoutsObservationTask?.cancel()
        workoutsObservationTask = Task {
            guard let useCase = fetchAssignedWorkoutsUseCase else { return }

            for await workouts in useCase.observe() {
                guard !Task.isCancelled else { break }
                assignedWorkouts = workouts
            }
        }
    }

    // MARK: - UI Helpers

    func selectTrainer(_ trainer: PersonalTrainer) {
        selectedTrainer = trainer
        showConnectionSheet = true
    }

    func dismissConnectionSheet() {
        showConnectionSheet = false
        selectedTrainer = nil
    }

    func clearError() {
        error = nil
    }

    func clearSearch() {
        searchQuery = ""
        Task { await searchTrainers() }
    }
}

