    // MARK: - Actions

    private func loadProfileData() async {
        // Load user name
        if let cachedName = UserDefaults.standard.string(forKey: "socialUserDisplayName"), !cachedName.isEmpty {
            userName = cachedName
        }

        // Load workout history stats
        if let historyRepo = resolver.resolve(WorkoutHistoryRepository.self) {
            do {
                let entries = try await historyRepo.listEntries()
                completedWorkouts = entries.count
                totalMinutes = entries.reduce(0) { $0 + ($1.durationMinutes ?? 0) }

                // Calculate streak
                let calendar = Calendar.current
                let today = calendar.startOfDay(for: Date())
                let sortedDates = entries.map { calendar.startOfDay(for: $0.date) }.sorted(by: >)
                if let mostRecent = sortedDates.first,
                   let yesterday = calendar.date(byAdding: .day, value: -1, to: today),
                   mostRecent >= yesterday {
                    var streak = 1
                    var currentDate = mostRecent
                    for date in sortedDates.dropFirst() {
                        let expected = calendar.date(byAdding: .day, value: -1, to: currentDate)!
                        if date == expected {
                            streak += 1
                            currentDate = date
                        } else if date == currentDate {
                            continue
                        } else {
                            break
                        }
                    }
                    streakDays = streak
                }
            } catch {
                #if DEBUG
                print("[Profile] Error loading history: \(error)")
                #endif
            }
        }

        if let profileRepo = resolver.resolve(UserProfileRepository.self) {
            userProfile = try? await profileRepo.loadProfile()
        }
    }

    private func loadEntitlement() async {
        #if DEBUG
        if DebugEntitlementOverride.shared.isEnabled {
            entitlement = DebugEntitlementOverride.shared.entitlement
            debugModeEnabled = true
            debugIsPro = DebugEntitlementOverride.shared.isPro
            return
        }
        #endif

        if let repo = entitlementRepository {
            do {
                entitlement = try await repo.currentEntitlement()
            } catch {
                print("Failed to load entitlement: \(error)")
            }
        }
    }

    private func restorePurchases() async {
        guard let repo = storeKitRepository else { return }
        let restored = await repo.service.restorePurchases()
        if restored {
            await loadEntitlement()
            restoreMessage = "settings.restore_success".localized
        } else {
            restoreMessage = "settings.restore_not_found".localized
        }
        showingRestoreAlert = true
    }

    private func openSupportURL() {
        if let url = URL(string: "mailto:support@fittoday.app") {
            UIApplication.shared.open(url)
        }
    }

    #if DEBUG
    private func handleDebugModeChange(_ enabled: Bool) {
        DebugEntitlementOverride.shared.isEnabled = enabled
        if enabled {
            debugIsPro = DebugEntitlementOverride.shared.isPro
            handleDebugProChange(debugIsPro)
        } else {
            Task { await loadEntitlement() }
        }
    }

    private func handleDebugProChange(_ isPro: Bool) {
        DebugEntitlementOverride.shared.isPro = isPro
        entitlement = DebugEntitlementOverride.shared.entitlement
    }
    #endif
}

